import * as THREE from 'three';

/**
 * createRandomizedTree - Hàm khởi tạo biến thể cây 3D tự nhiên không trùng lặp
 * Tự động ngẫu nhiên hóa Tỷ lệ Scale, Góc Xoay 360°, Tông màu lá & Cành phụ đâm ngang.
 * @returns {THREE.Group} Đối tượng THREE.Group cái cây 3D tự nhiên ngẫu nhiên
 */
export function createRandomizedTree() {
  const treeGroup = new THREE.Group();

  // =========================================================
  // 1. TẠO TÔNG MÀU LÁ VÀ THÂN NGẪU NHIÊN (COLOR VARIATIONS)
  // =========================================================
  // Tự động dịch chuyển sắc độ xanh lá nhẹ ngẫu nhiên cho từng cây
  const greenHues = [
    { dark: 0x1b4332, mid: 0x2d6a4f, fresh: 0x40916c, sun: 0x52b788 }, // Xanh lục bảo mượt
    { dark: 0x143626, mid: 0x23533c, fresh: 0x347455, sun: 0x47976f }, // Xanh lá thông thẫm
    { dark: 0x284b25, mid: 0x3b6e37, fresh: 0x50934b, sun: 0x69b863 }, // Xanh rêu tươi rực rỡ
    { dark: 0x1c3a27, mid: 0x2e5c3e, fresh: 0x428258, sun: 0x58aa74 }  // Xanh ngọc mạ
  ];

  const selectedHue = greenHues[Math.floor(Math.random() * greenHues.length)];

  const leafMatDark = new THREE.MeshStandardMaterial({ color: selectedHue.dark, roughness: 0.8, flatShading: true });
  const leafMatMid = new THREE.MeshStandardMaterial({ color: selectedHue.mid, roughness: 0.8, flatShading: true });
  const leafMatFresh = new THREE.MeshStandardMaterial({ color: selectedHue.fresh, roughness: 0.8, flatShading: true });
  const leafMatSun = new THREE.MeshStandardMaterial({ color: selectedHue.sun, roughness: 0.8, flatShading: true });

  const barkMat = new THREE.MeshStandardMaterial({
    color: 0x3a2518,
    roughness: 0.9,
    flatShading: true,
    metalness: 0.05
  });

  // =========================================================
  // 2. THÂN, GỐC CÂY & CÀNH NGHỆ THUẬT (TRUNK & SUB-BRANCHES)
  // =========================================================
  // 2a. Gốc cây phình to sát mặt đất
  const baseMesh = new THREE.Mesh(new THREE.CylinderGeometry(0.38, 0.58, 0.6, 8), barkMat);
  baseMesh.position.set(0, 0.3, 0);
  baseMesh.castShadow = true;
  baseMesh.receiveShadow = true;
  treeGroup.add(baseMesh);

  // 2b. Thân chính thon nhỏ
  const trunk = new THREE.Mesh(new THREE.CylinderGeometry(0.2, 0.38, 3.8, 8), barkMat);
  trunk.position.set(0, 2.1, 0);
  trunk.rotation.z = (Math.random() - 0.5) * 0.12; // Uốn cong ngẫu nhiên
  trunk.castShadow = true;
  trunk.receiveShadow = true;
  treeGroup.add(trunk);

  // 2c. 3 Cành phụ đỡ tán lá
  const branchConfigs = [
    { rTop: 0.05, rBot: 0.14, h: 1.6, x: 0.32, y: 3.3, z: 0.22, rx: 0.45, ry: 0, rz: -0.5 },
    { rTop: 0.04, rBot: 0.13, h: 1.5, x: -0.3, y: 3.4, z: -0.25, rx: -0.4, ry: 2.1, rz: 0.45 },
    { rTop: 0.04, rBot: 0.12, h: 1.4, x: 0.15, y: 3.6, z: -0.32, rx: 0.35, ry: 4.2, rz: 0.38 }
  ];

  branchConfigs.forEach(b => {
    const branch = new THREE.Mesh(new THREE.CylinderGeometry(b.rTop, b.rBot, b.h, 6), barkMat);
    branch.position.set(b.x, b.y, b.z);
    branch.rotation.set(b.rx, b.ry, b.rz);
    branch.castShadow = true;
    branch.receiveShadow = true;
    treeGroup.add(branch);
  });

  // 2d. NGẪU NHIÊN: Thêm 1 hoặc 2 nhánh cành mỏng đâm ngang ngẫu nhiên ra ngoài tán lá
  const extraBranchCount = 1 + Math.floor(Math.random() * 2);
  for (let eb = 0; eb < extraBranchCount; eb++) {
    const extraBranch = new THREE.Mesh(new THREE.CylinderGeometry(0.02, 0.07, 1.2, 6), barkMat);
    const angle = Math.random() * Math.PI * 2;
    extraBranch.position.set(Math.cos(angle) * 0.4, 3.8 + eb * 0.5, Math.sin(angle) * 0.4);
    extraBranch.rotation.set(Math.random() * 0.8, angle, (Math.random() - 0.5) * 0.8);
    extraBranch.castShadow = true;
    treeGroup.add(extraBranch);
  }

  // =========================================================
  // 3. TÁN LÁ ĐA DIỆN LOW-POLY ĐAN XEN (FOLIAGE CLUSTERS)
  // =========================================================
  const clusterConfigs = [
    { type: 'dodeca', radius: 1.6, posX: 0, posY: 4.6, posZ: 0, scaleX: 1.2, scaleY: 1.1, scaleZ: 1.2, mat: leafMatMid },
    { type: 'icosa', radius: 1.2, posX: -0.9, posY: 4.9, posZ: 0.5, scaleX: 1.1, scaleY: 1.0, scaleZ: 1.1, mat: leafMatFresh },
    { type: 'dodeca', radius: 1.25, posX: 0.85, posY: 4.7, posZ: -0.4, scaleX: 1.05, scaleY: 1.0, scaleZ: 1.1, mat: leafMatSun },
    { type: 'icosa', radius: 1.1, posX: 0.35, posY: 4.0, posZ: 0.75, scaleX: 1.15, scaleY: 0.9, scaleZ: 1.05, mat: leafMatDark },
    { type: 'dodeca', radius: 0.85, posX: -0.25, posY: 5.8, posZ: -0.15, scaleX: 0.95, scaleY: 1.0, scaleZ: 0.95, mat: leafMatSun }
  ];

  clusterConfigs.forEach(c => {
    const geo = (c.type === 'dodeca')
      ? new THREE.DodecahedronGeometry(c.radius, 1)
      : new THREE.IcosahedronGeometry(c.radius, 0);

    const clusterMesh = new THREE.Mesh(geo, c.mat);
    clusterMesh.position.set(c.posX, c.posY, c.posZ);
    clusterMesh.scale.set(c.scaleX, c.scaleY, c.scaleZ);
    clusterMesh.rotation.set(Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI);
    clusterMesh.castShadow = true;
    clusterMesh.receiveShadow = true;
    treeGroup.add(clusterMesh);
  });

  // Lá rơi lơ lửng bên dưới
  const fallingLeaf1 = new THREE.Mesh(new THREE.DodecahedronGeometry(0.22, 0), leafMatFresh);
  fallingLeaf1.position.set(-0.75, 3.2, 0.65);
  fallingLeaf1.castShadow = true;
  treeGroup.add(fallingLeaf1);

  // =========================================================
  // 4. NGẪU NHIÊN HÓA GÓC XOAY 360° & TỶ LỆ SCALE (0.8x - 1.35x)
  // =========================================================
  // Ngẫu nhiên góc xoay Y (0 đến 360 độ) để các mặt phẳng đa diện bắt sáng hoàn toàn khác nhau!
  treeGroup.rotation.y = Math.random() * Math.PI * 2;

  // Ngẫu nhiên chiều cao (scale.y) và chiều rộng (scale.x, scale.z) từ 0.85x đến 1.35x
  const scaleXZ = 1.0 + (Math.random() - 0.5) * 0.45; // 0.8x - 1.25x
  const scaleY = 1.05 + (Math.random() - 0.5) * 0.45; // 0.8x - 1.35x
  treeGroup.scale.set(scaleXZ * 1.25, scaleY * 1.25, scaleXZ * 1.25);

  return treeGroup;
}

export const createPremiumStylizedTree = createRandomizedTree;
export const createStylizedTree = createRandomizedTree;
export const createAdvancedStylizedTree = createRandomizedTree;
